export async function linkNeptune(
    fromResourceID: string,
    toResourceID: string,
    edgeLabel: string,
    attributes: Map<string, any> = new Map(),
    fromLabel?: string,
    fromResourceType?: number,
    toLabel?: string,
    toResourceType?: number,
): Promise<void> {
    if (!fromLabel || fromResourceType === undefined) {
        throw new Error(`linkNeptune: fromLabel and fromResourceType are required (edge ${edgeLabel} ${fromResourceID} -> ${toResourceID})`);
    }
    if (!toLabel || toResourceType === undefined) {
        throw new Error(`linkNeptune: toLabel and toResourceType are required (edge ${edgeLabel} ${fromResourceID} -> ${toResourceID})`);
    }

    try {
        attributes.set(DatabaseFields.CREATED, Date.now());
        attributes.set(DatabaseFields.UPDATED, Date.now());
        attributes.set(DatabaseFields.INSERTED_LONG, Date.now());
        attributes.set(DatabaseFields.UPDATED_LONG, Date.now());
        attributes.set(DatabaseFields.ACCOUNTID, currentEvent['accountID']);
        attributes.set(DatabaseFields.REGION, currentEvent['region']);
        attributes.set(DatabaseFields.CUSTOMER, currentEvent['org']['client']);
        attributes.set(DatabaseFields.CLOUD, currentEvent['cloud']);

        console.log(`linkNeptune ${fromResourceID} ${edgeLabel} ${toResourceID}`, JSON.stringify([...attributes]));

        // Ensure both endpoints exist with the correct label/resourceType.
        // Routes through emptyCreate so placeholders are never created with the
        // generic 'vertex' label (which Neptune cannot relabel later).
        await emptyCreate(currentEvent as RunEvent, fromResourceID, fromLabel, new Map(), fromResourceType);
        await emptyCreate(currentEvent as RunEvent, toResourceID, toLabel, new Map(), toResourceType);

